// 1991: Project 'Oak' begins.
// 1995: Officially released as Java 1.0.
// Today: Billions of devices run Java globally.

// 1. JDK (Java Development Kit)
// A collection of tools used for developing and running Java programs.

// 2. JRE (Java Runtime Environment)
// Helps in executing programs developed in Java.

// 3. JVM (Java Virtual Machine)
// The engine inside the JRE that actually interprets the Bytecode into Machine Code.

// THE CLASS (The Paper Blueprint)
class Car { 
    int doors = 4;
    void honkHorn() { }
}

// THE OBJECT (The Physical Engine in Memory)
// We use the 'new' keyword to build a physical object from the Blueprint!
Car myToyota = new Car(); 
Car myHonda = new Car();

package com.company; // Organizes files into folders

public class Main { 
    // ALL of your code, variables, and methods MUST go inside here.
    // If you write code outside these curly braces, the compiler crashes.
}

public static void main(String[] args) {
    System.out.println("Hello World");
}

// 1. PascalCase (Strictly for Blueprints)
// Rule: The first letter of EVERY word is Capitalized.
// Applies to: Classes and Interfaces
class CodeWithHarry { }
class PlayerInventory { }

// 2. camelCase (Strictly for Actions & Storage)
// Rule: First letter is lowercase, subsequent words are Capitalized.
// Applies to: Variables and Methods (Functions)
int myMarks = 100;
void calculateFinalScore() { }

// 3. UPPER_SNAKE_CASE (Strictly for Locked Data)
// Rule: ALL CAPS, with words separated by underscores.
// Applies to: Named Constants (using the 'final' keyword)
final double PI_VALUE = 3.14159;
final int MAX_CAPACITY = 5000;

// Simple Variable (Raw Data Only)
int age = 21;

// Object Variable (Comes with built-in methods!)
Scanner input = new Scanner(System.in);

// We can call methods on Objects, but NOT on simple variables!
// age.doSomething(); -> ERROR! Primitives don't have methods.

// 1. byte (8 bits): The smallest box.
byte tinyNum = 127; 

// 2. short (16 bits): For small counters.
short smallNum = 32767; 

// 3. int (32 bits): The industry standard.
int score = 2147483647; 

// 4. long (64 bits): For massive numbers.
long debt = 9223372036854775807L; // Requires an 'L' at the end!

// 1. float (32 bits): Standard precision.
float temperature = 98.6f; // Requires an 'f' at the end!

// 2. double (64 bits): High precision (Industry standard).
double atomSize = 0.00000000532;

// 3. Scientific Notation (E-notation)
// Supported natively by the double data type!
double lightSpeed = 3.0e10; // Evaluates to 3.0 x 10^10 (30,000,000,000.0)

// Method 1: Two-Step (Declaration, then Initialization)
int age;
age = 21;

// Method 2: Single-Line (The Industry Standard)
double cashAmount = 150.75;

// Method 3: Multiple Declarations
// Creates three empty integer boxes at once to save space
int x, y, z;

// UPDATING (Assignment Statement)
// Later in the program, you can overwrite the data:
cashAmount = 200.00; // The 150.75 is permanently deleted and replaced.
